import matplotlib.pyplot as plt
import numpy as np
import pandas as pd
# 모델, 독립변수, 종속변수, 축, 제목
def plot_decision_boundary(clf, X, y, title, filename):
  # x축 범위값
  x_min, x_max = X[:,0].min()-0.5, X[:,0].max()+0.5
  # y축 범위값
  y_min, y_max = X[:,1].min()-0.5, X[:,1].max()+0.5
  xx, yy = np.meshgrid( # 90000개의 정점
      np.linspace(x_min, x_max, 300),
      np.linspace(y_min, y_max, 300)
  )
  # 결과값 0, 1
  # column으로 묶어서 예측
  Z = clf.predict(np.c_[xx.ravel(), yy.ravel()])
  Z = Z.reshape(xx.shape)
  # color로 채운 등고선
  plt.contourf(xx, yy, Z, alpha=0.3)
  plt.scatter(X[:,0], X[:,1], c=y, edgecolor='k')
  plt.title(title)
  plt.savefig(filename, dpi=300)
  plt.show()

from pathlib import Path

IMAGES_PATH = Path() / "images" / "ensembles"
IMAGES_PATH.mkdir(parents=True, exist_ok=True)
def save_fig(fig_id, tight_layout=True, fig_extension="png", resolution=300):
  path = IMAGES_PATH / f"{fig_id}.{fig_extension}"
  if tight_layout:
    plt.tight_layout()
  plt.savefig(path, format=fig_extension, dpi=resolution)

from sklearn.preprocessing import PolynomialFeatures
from sklearn.linear_model import LinearRegression
from sklearn.pipeline import make_pipeline
# 비선형회귀
# dict 형 데이터를 분리
def PolynomialRegression(degree=2, **kwargs):
  return make_pipeline(PolynomialFeatures(degree),
                       LinearRegression(**kwargs))

def make_data(N, err=1.0, rseed=1):
  rng = np.random.RandomState(rseed)
  X = rng.rand(N, 1) ** 2
  y = 10 - 1. / (X.ravel() + 0.1) # 종속변수 수식
  if err > 0: # noise 부여
    y += err * rng.randn(N) # err는 random한 수식의 개수
  return X, y
X, y = make_data(40)

# 독립 변수 2차원입력
X_test = np.linspace(-0.1, 1.1, 500)[:, None] # 차수만 증가

# 시각화 x,y를 대입 (시각화 1차원)
plt.scatter(X.ravel(), y, color='black')
axis = plt.axis()
for degree in [1, 3, 5]:
  y_test = PolynomialRegression(degree).fit(X, y).predict(X_test)
  plt.plot(X_test.ravel(), y_test, label='degree={0}'.format(degree))
plt.xlim(-0.1, 1.0)
plt.ylim(-2, 12)
plt.legend(loc='best')

# parameter tunning (접근 이름은 자동으로 부여)
PolynomialRegression().steps

PolynomialRegression().get_params().items()

from sklearn.model_selection import GridSearchCV
# 20차원, fit_intercept
param_grid = {'polynomialfeatures__degree': np.arange(21),
              'linearregression__fit_intercept': [True, False]}
grid = GridSearchCV(PolynomialRegression(), param_grid, cv=7)
# 21 * 2 * 7

grid.fit(X, y)

grid.get_params

grid.cv_results_

grid.cv_results_['mean_test_score']

grid.best_estimator_

model = grid.best_estimator_ # best_params가 적용된 모델
plt.scatter(X.ravel(), y) # 시각화 할 때는 1차원
lim = plt.axis()
y_test = model.fit(X, y).predict(X_test)
plt.plot(X_test.ravel(), y_test)
plt.axis(lim)

