from matplotlib.colors import ListedColormap
def plot_decision_boundary(clf, X, y, axes=[0, 7.5, 0, 3], 
    iris=True,  legend=False, plot_training=True):
    x1s = np.linspace(axes[0], axes[1], 100)
    x2s = np.linspace(axes[2], axes[3], 100)
    x1, x2 = np.meshgrid(x1s, x2s)
    print(x1.shape, x2.shape)
    X_new = np.c_[x1.ravel(), x2.ravel()]
    y_pred = clf.predict(X_new).reshape(x1.shape)
    custom_cmap = ListedColormap(['#fafab0','#9898ff','#a0faa0'])
    plt.contourf(x1, x2, y_pred, alpha=0.3, cmap=custom_cmap)
    if not iris:
        custom_cmap2 = ListedColormap(['#7d7d58','#4c4c7f',
                                       '#507d50'])
        plt.contour(x1, x2, y_pred, cmap=custom_cmap2, alpha=0.8)
    if plot_training:
        plt.plot(X[:, 0][y==0], X[:, 1][y==0], "yo",label="Iris-Setosa")
        plt.plot(X[:, 0][y==1], X[:, 1][y==1], "bs",label="Iris-Versicolor")
        plt.plot(X[:, 0][y==2], X[:, 1][y==2], "g^",label="Iris-Virginica")
        plt.axis(axes)
    if iris:
        plt.xlabel("꽃잎 길이", fontsize=14)
        plt.ylabel("꽃잎 너비", fontsize=14)
    else:
        plt.xlabel(r"$x_1$", fontsize=18)
        plt.ylabel(r"$x_2$", fontsize=18, rotation=0)
    if legend:
        plt.legend(loc="lower right", fontsize=14)

# 트리의 특징 : 수평과 수직으로 분할
# 트리는 회전에 민감
# 정직교 축으로 회전
# 주성분으로 데이터를 회전시킴 (새로운 축)
# PCA처럼 데이터를 회전하면 과적합을 피할 수도 있고 과적합할 수도 있음
# 왼쪽모델 : 기본 모델, 오른쪽모델 : 데이터를 45도 회전한 다음 DT한 결과
np.random.seed(6)
X_square = np.random.rand(100, 2) - 0.5
y_square = (X_square[:, 0] > 0).astype(np.int64)
angle = np.pi / 4 # 45도
# 회전행렬
rotation_matrix = np.array([[np.cos(angle), -np.sin(angle)], [np.sin(angle), np.cos(angle)]])
# 행렬곱을 통해서 데이터 회전
X_rotated_square = X_square.dot(rotation_matrix)
# 원래 데이터 모델
tree_clf_square = DecisionTreeClassifier(random_state=42)
tree_clf_square.fit(X_square, y_square)
# 회전한 데이터 모델
tree_clf_rotated_square = DecisionTreeClassifier(random_state=42)
tree_clf_rotated_square.fit(X_rotated_square, y_square)
# 열분할 후 시각화, 축공유 (y)
fig, axes = plt.subplots(ncols=2, figsize=(10, 4), sharey=True)
plt.sca(axes[0])
plot_decision_boundary(tree_clf_square, X_square, y_square, axes=[-0.7, 0.7, -0.7, 0.7])
plt.sca(axes[1])
plot_decision_boundary(tree_clf_rotated_square, X_rotated_square, y_square, axes=[-0.7, 0.7, -0.7, 0.7])
plt.ylabel("")
save_fig("sensitivity_to_rotation_plot")
plt.show()

from sklearn.model_selection import train_test_split
from sklearn.pipeline import Pipeline, make_pipeline
from sklearn.preprocessing import StandardScaler
from sklearn.model_selection import GridSearchCV
import pandas as pd
winedf = pd.read_csv('/content/drive/MyDrive/AI빅데이터_파이썬/dataset/winequality-red.csv', sep=";")
print(winedf.head(3))
X=winedf.drop(['quality'], axis=1)
Y=winedf['quality']
Y.unique()

X_train, X_test, y_train, y_test = train_test_split(
    X, Y, test_size=0.2, random_state=30, stratify=Y
)
# 층화추출
# 명시적 명명
# pipeline에서는 클래스를 사용해서 진행
steps = [('scaler', StandardScaler()), ('DT', DecisionTreeClassifier(random_state=42))]
pipeline = Pipeline(steps) # 파이프라인 인스턴스
# 이름을 만드는 규칙 : 파이프라인 명명된 이름__원하는 파라미터
parameters = {
    'DT__max_depth': [4, 6, 8, 10, 12],
    'DT__min_samples_split': [2, 5, 10]
}
grid = GridSearchCV(pipeline, param_grid=parameters, cv=5)
grid.fit(X_train, y_train)
print("score = %3.2f" % (grid.score(X_test, y_test)))
print(grid.best_params_)

from sklearn.metrics import *
from sklearn.model_selection import cross_val_score
print(accuracy_score(y_test, grid.predict(X_test))) # 정확도

cross_val_score(grid, X_test, y_test, cv=2)

# 비율에 맞추어서
pd.Series(y_train).value_counts(normalize=True)

pd.Series(y_test).value_counts(normalize=True)

grid.best_estimator_

# 연속적 데이터가 파라미터로 들어올 때
from sklearn.model_selection import RandomizedSearchCV
rand_search = RandomizedSearchCV( # 최적의 방향으로 조합해서 테스트
    pipeline,
    param_distributions=parameters,
    n_iter=10, # 몇 개의 조합을 테스트 할 것인지
    cv=5,
    random_state=42,
    n_jobs=-1 # 모든 코어를 동원해서
)
rand_search.fit(X_train, y_train)
print("score = %3.2f" % (rand_search.score(X_test, y_test)))
print(rand_search.best_params_)

from sklearn.experimental import enable_halving_search_cv
from sklearn.model_selection import HalvingRandomSearchCV
# 전체 데이터가 아니라 처음에 일부 데이터만 주고 빨리 테스트
# 결과가 안좋은 조합은 버림
# 조합은 줄이고 데이터는 늘리면서 테스트 함
halving_search = HalvingRandomSearchCV(
    pipeline,
    param_distributions=parameters,
    factor=3, # 조합의 1/3만 남기고 버림
    cv=5,
    random_state=42,
    n_jobs=-1
)
halving_search.fit(X_train, y_train)
print("score = %3.2f" % (halving_search.score(X_test, y_test)))
print(halving_search.best_params_)

