# RandomForest
from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score

from sklearn.datasets import make_moons
# 학습 시 - 선형분류가 어려운 데이터
X, y = make_moons(n_samples=600, noise=0.3, random_state=42)
X_train, X_test, y_train, y_test = train_test_split(
    X, y, test_size=0.3, random_state=0, stratify=y
)
dt = DecisionTreeClassifier(max_depth=None, random_state=0)
# 단점 : 과적합, 변수 입력 순서에 따라서 결과가 달라짐 (트리 모양)

# random하게 sampling (복원추출), 열선택
# Bias를 개선 : Adaboost, Gradient Boost
rf = RandomForestClassifier(
    n_estimators=200, # DT로 구성 -> 평균, 투표 -> Variance
    max_depth=None,
    oob_score=True, # 36.8% out of bag -> 학습 미참여 데이터
    # 테스트까지 진행
    n_jobs=-1, # 병렬처리
    random_state=0
)

# scikits fit -> transform -> predict
dt.fit(X_train, y_train)
rf.fit(X_train, y_train)

metrics = {
    "Model": ["Decision Tree", "RandomForest"],
    "Train Acc.": [
        accuracy_score(y_train, dt.predict(X_train)),
        accuracy_score(y_train, rf.predict(X_train))
    ],
    "Test Acc.": [
        accuracy_score(y_test, dt.predict(X_test)),
        accuracy_score(y_test, rf.predict(X_test)),
    ]
}

# RF의 test, OOB 결과 비교
metrics_df = pd.DataFrame(metrics)
metrics_df.loc[metrics_df["Model"] == "RandomForest",
               "OOB Score"] = getattr(rf, "oob_score_", np.nan)

plot_decision_boundary(dt, X, y, "Decision Tree: decision boundary", "./dt_boundary.png")
plot_decision_boundary(rf, X, y, "Random Forest: decision boundary", "./rf_boundary.png")

# 변수 중요도 출력
rf_importances = pd.DataFrame({
    "feature": ["x1", "x2"],
    "importance": rf.feature_importances_ # 변수 중요도
}).sort_values("importance", ascending=False).reset_index(drop=True) # descending 정렬

print("RF_Feature_importances", rf_importances)

# max_features 효과비교
# 값을 작게 해주면 random한 모델들이 만들어지고 일반화된 모델이 생성
# 8개의 변수 2값, 8개이면 조합이 작아 짐
# 작게 주면 분산을 줄여서 일반화
# 크게 주면 모델이 같아 짐 -> 과적합
X, y = make_moons(n_samples=800, noise=0.3, random_state=42)
params = [1, 2, None]
plt.figure(figsize=(15, 4))
for i, mf in enumerate(params, 1): # 1부터 시작
  clf = RandomForestClassifier(n_estimators=200,
                               max_features=mf, random_state=42).fit(X, y)
  x_min, x_max = X[:, 0].min() - .5, X[:, 0].max() + .5
  y_min, y_max = X[:, 1].min() - .5, X[:, 1].max() + .5
  xx, yy = np.meshgrid(np.linspace(x_min, x_max, 300), np.linspace(y_min, y_max, 300))
  # x,y 값 조합으로 예측
  Z = clf.predict(np.c_[xx.ravel(), yy.ravel()]).reshape(xx.shape)
  plt.subplot(1, 3, i)
  plt.contourf(xx, yy, Z, alpha=0.3) # 높이값 2 -> 컬러값
  plt.scatter(X[:, 0], X[:, 1], c=y, edgecolor="k", s=20)
  plt.title(f"max_features={mf}")
plt.suptitle("RandomForest", fontsize=14)
plt.show()

# Regressor vs AdaBoostRegressor
# 차이점
# Regressor는 기울기와 절편 -> 무한대 예측 가능 : 최소제곱법 - 기울기, 절편
# Tree에서의 회귀는 데이터가 있는 부분까지만 가능
# Adaboost
from sklearn.ensemble import AdaBoostRegressor
from sklearn.tree import DecisionTreeRegressor

rng = np.random.RandomState(1)
X = np.linspace(0, 6, 100)[:, np.newaxis]
y = np.sin(X).ravel() + np.sin(6 * X).ravel() + rng.normal(0, 0.1, X.shape[0])
regr_1 = DecisionTreeRegressor(max_depth=6) # 톱니바퀴 형태
# 점점 가중치를 부여하고 강화된 모델로 개선
# RandomForest는 500개
# AdaBoostRegressor 6~7개
# 데이터를 부족한 내용을 보충해서 스스로 추가 제공
# 데이터 가중치

# 규제를 하는 이유 : 과적합 방지하고 일반화된 모델을 만들기 위해서
# meta-estimator
# estimator__max_depth
regr_2 = AdaBoostRegressor(estimator=DecisionTreeRegressor(max_depth=6), n_estimators=300, random_state=rng)

regr_1.fit(X, y)
regr_2.fit(X, y)
y_1 = regr_1.predict(X)
y_2 = regr_2.predict(X)
plt.figure()
plt.scatter(X, y, c="k", label="학습데이터")
plt.plot(X, y_1, c="g", label="예측기1개", linewidth=2)
plt.plot(X, y_2, c="r", label="예측기300개", linewidth=2)
plt.xlabel("data")
plt.ylabel("target")
plt.title("ADA Boost")
