# 같은 내용을 Gradientboost 모델에도 같은 내용으로 최적화하시오
# AdaBoost vs Gradientboost는 차이가 있음
# AdaBoost (estimator가 있음) : estimator가 있어서 다른 모델도 boosting이 가능
# Gradientboost는 base estimator가 DcisionTree이기 때문에 없음
# Gradientboost는 오로지 DT위에서만 작동
from sklearn.ensemble import GradientBoostingRegressor

gbr = GradientBoostingRegressor()

params = {
    'max_depth': range(1, 11),
    'n_estimators': range(50, 1001, 50)
}

grid_search = GridSearchCV(
    gbr,
    param_grid=params,
    cv=5,
    n_jobs=-1
)

grid_search.fit(X, y)

print(grid_search.best_score_)
print(grid_search.best_params_)